const V9='';
import { execSync } from 'child_process';
import fs from 'fs';
const TOKG=process.env.GH_TOKEN, REPO=process.env.GH_REPO||'raimis079-creator/petshop-bridge';
const U=process.env.WP_USER||'', P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const AUTH='-u "'+U+':'+P+'"';
function wj(m,path,body){fs.writeFileSync('/tmp/wbody.json', JSON.stringify(body));
  return execSync('curl -sk '+AUTH+' -X '+m+' -H "Content-Type: application/json" --data-binary @/tmp/wbody.json "https://dev.avesa.lt/wp-json/'+path+'"',{maxBuffer:80*1024*1024,timeout:90000}).toString();}
function pr(n,o){const u='https://api.github.com/repos/'+REPO+'/contents/screenshots/'+n;let s='';
 for(let i=0;i<6;i++){try{const j=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+TOKG+'" "'+u+'?nocache='+Math.random()+'"').toString());if(j.sha)s=j.sha;}catch(e){}
  fs.writeFileSync('/tmp/pj.json',JSON.stringify({message:'r',content:Buffer.from(JSON.stringify(o)).toString('base64'),...(s?{sha:s}:{})}));
  const c=execSync('curl -s -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: Bearer '+TOKG+'" -d @/tmp/pj.json "'+u+'"').toString().trim();
  if(c==='200'||c==='201')return c; execSync('sleep 2'); }return 'fail';}
const o={};
// 1) GET current 572 (scope/active) + backup code
let cur; try{ cur=JSON.parse(execSync('curl -sk '+AUTH+' "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/572"',{maxBuffer:80*1024*1024}).toString()); }catch(e){ o.geterr=String(e).slice(0,150); }
o.before={scope:cur&&cur.scope, active:cur&&cur.active, name:cur&&cur.name, code_len:cur&&cur.code?cur.code.length:0};
// backup current code to repo
if(cur&&cur.code){ pr('backup_dp_572_v8.txt.json', {code:cur.code}); }
// 2) UPDATE 572 with v9
const v9code=Buffer.from(V9,'base64').toString('utf8');
const body={id:572, name:'Petshop Daugiau=Pigiau Šablono Kūrimo Forma v9', code:v9code, active:true};
if(cur&&cur.scope) body.scope=cur.scope;
let upd; try{ upd=wj('POST','code-snippets/v1/snippets/572',body); }catch(e){ upd=String(e).slice(0,300); }
o.update_resp = upd.slice(0,400);
// 3) verify
let after; try{ after=JSON.parse(execSync('curl -sk '+AUTH+' "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/572"',{maxBuffer:80*1024*1024}).toString()); }catch(e){ o.aftererr=String(e).slice(0,150); }
o.after={active:after&&after.active, name:after&&after.name, code_len:after&&after.code?after.code.length:0, has_helper:!!(after&&after.code&&after.code.indexOf('petshop_dp_apply_calculator_data')>=0)};
console.log('PUT:',pr('dp_deploy_v9.json',o));
